import { useContext, useEffect, useState } from "react";
import { AuthContext } from "./AuthContext";

export default function ClubDetail() {
    const { user } = useContext(AuthContext);
    const [club, setClub] = useState(null);
    const [news, setNews] = useState([]);
    const [members, setMembers] = useState([]);
    const [pending, setPending] = useState([]);
    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    const clubId = (() => {
        const m = (window.location.hash||"").match(/^#\/clubs\/(\d+)/i);
        return m ? Number(m[1]) : null;
    })();

    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";
    const isLeader = !!user && members.some(m => m.userId === user.id && m.role === "LEADER");
    const canManage = isAdmin || isLeader;

    useEffect(() => {
        if (!clubId) return;
        (async ()=>{
            const [c, n, m] = await Promise.all([
                fetch(`/api/clubs/${clubId}`).then(r=>r.json()),
                fetch(`/api/clubs/${clubId}/news`).then(r=>r.json()),
                fetch(`/api/clubs/${clubId}/members`).then(r=>r.json())
            ]).catch(()=>[null,[],[]]);
            setClub(c); setNews(Array.isArray(n)?n:[]); setMembers(Array.isArray(m)?m:[]);
            if (user) {
                fetch(`/api/clubs/${clubId}/join-requests?requesterEmail=${encodeURIComponent(user.email)}`)
                    .then(r => r.ok ? r.json() : [])
                    .then(setPending)
                    .catch(()=>setPending([]));
            }
        })();
    }, [clubId, user?.email]);

    const decide = async (requestId, decision) => {
        const url = `/api/clubs/${clubId}/join-requests/${requestId}/decision?requesterEmail=${encodeURIComponent(user.email)}&decision=${decision}`;
        const res = await fetch(url, { method:"POST" });
        const body = await res.json().catch(()=>({}));
        if (!res.ok) { alert(body.message || "Failed"); return; }
        // Refresh members + pending
        const [m, p] = await Promise.all([
            fetch(`/api/clubs/${clubId}/members`).then(r=>r.json()),
            fetch(`/api/clubs/${clubId}/join-requests?requesterEmail=${encodeURIComponent(user.email)}`).then(r=>r.json())
        ]);
        setMembers(m); setPending(p);
    };

    const postNews = async (e) => {
        e.preventDefault();
        const res = await fetch(`/api/clubs/${clubId}/news?requesterEmail=${encodeURIComponent(user.email)}`, {
            method:"POST",
            headers:{"Content-Type":"application/json"},
            body: JSON.stringify({ title, content })
        });
        const body = await res.json().catch(()=>({}));
        if (!res.ok) { alert(body.message || "Failed"); return; }
        setNews(prev=>[body, ...prev]); setTitle(""); setContent("");
    };

    const deleteNews = async (newsId) => {
        const res = await fetch(`/api/clubs/${clubId}/news/${newsId}?requesterEmail=${encodeURIComponent(user.email)}`, { method: "DELETE" });
        if (!res.ok) { const b = await res.json().catch(()=>({})); alert(b.message || "Failed"); return; }
        setNews(prev=>prev.filter(n=>n.id!==newsId));
    };

    if (!clubId) return <div style={{padding:20}}><a href="#/clubs">← Back</a></div>;
    if (!club) return <div style={{padding:20}}>Loading…</div>;

    return (
        <div style={{maxWidth:1000, margin:"0 auto", padding:20}}>
            <a href="#/clubs" style={{textDecoration:"none"}}>← Back</a>
            <h2>{club.name}</h2>
            <p>{club.description}</p>

            <div style={{display:"grid", gridTemplateColumns:"2fr 1fr", gap:16}}>
                {/* News column */}
                <div>
                    <h3>Club News</h3>

                    {canManage && (
                        <form onSubmit={postNews} style={{display:"grid", gap:8, marginBottom:12}}>
                            <input placeholder="Title" value={title} onChange={e=>setTitle(e.target.value)} required/>
                            <textarea placeholder="Content" value={content} onChange={e=>setContent(e.target.value)} required/>
                            <button type="submit">Post</button>
                        </form>
                    )}

                    {news.map(n=>(
                        <div key={n.id} style={{border:"1px solid #ddd", borderRadius:8, padding:10, marginBottom:10}}>
                            <div style={{display:"flex", justifyContent:"space-between", alignItems:"center"}}>
                                <strong>{n.title}</strong>
                                {canManage && <button onClick={()=>deleteNews(n.id)} style={{background:"#b00020", color:"#fff", border:"none", borderRadius:6, padding:"4px 8px"}}>Delete</button>}
                            </div>
                            <div style={{whiteSpace:"pre-wrap"}}>{n.content}</div>
                            <div style={{opacity:.7, fontSize:12, marginTop:6}}>
                                {n.createdAt ? new Date(n.createdAt).toLocaleString() : ""}
                            </div>
                        </div>
                    ))}
                    {news.length===0 && <p>No news yet.</p>}
                </div>

                {/* Members & requests */}
                <div>
                    <h3>Members</h3>
                    <ul>
                        {members.map(m=>(
                            <li key={m.id}>{m.userId} — {m.role}</li>
                        ))}
                    </ul>

                    {canManage && (
                        <>
                            <h3>Pending Requests</h3>
                            {pending.length===0 && <p>No pending requests.</p>}
                            {pending.map(r=>(
                                <div key={r.id} style={{border:"1px solid #eee", padding:8, borderRadius:6, marginBottom:8}}>
                                    <div>Request ID: {r.id}</div>
                                    <div>User ID: {r.userId}</div>
                                    <div style={{marginTop:6, display:"flex", gap:8}}>
                                        <button onClick={()=>decide(r.id,"approve")}>Approve</button>
                                        <button onClick={()=>decide(r.id,"reject")}>Reject</button>
                                    </div>
                                </div>
                            ))}
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}
